from collections import deque

class Solution(object):
    def minimumOperationsToMakeEqual(self, x, y):
        if x <= y:
            return y - x
        dist = {x: 0}
        q = deque([x])
        while q:
            cur = q.popleft()
            d = dist[cur]
            candidates = [cur - 1, cur + 1]
            if cur % 5 == 0: candidates.append(cur // 5)
            if cur % 11 == 0: candidates.append(cur // 11)
            for nxt in candidates:
                if nxt < 0 or nxt > x + abs(x - y):
                    continue
                if nxt == y:
                    return d + 1
                if nxt not in dist:
                    dist[nxt] = d + 1
                    q.append(nxt)
        return abs(x - y)
